const wfData = $('Webhook').first().json.body;
const msg = wfData.message;
const userId = wfData.userId || 'anon';
const sessionId = wfData.sessionId || 'av_' + Date.now();
const businessName = wfData.businessName || 'Cala Blanca';
const history = wfData.history || [];

let visitorName = '';
const nameMatch = msg.match(/(?:me llamo|soy|mi nombre es)\s+([A-Za-zÁÉÍÓÚÑáéíóúñ]+(?:\s+[A-Za-zÁÉÍÓÚÑáéíóúñ]+)*)/i);
if (nameMatch) visitorName = nameMatch[1].trim();

let visitorContact = '';
const phoneMatch = msg.match(/(?:tel[eé]fono|celular|m[oó]vil|whatsapp|contacto|ll[aá]mame|mi numero|mi n[uú]mero)[^\d]*(\d{7,})/i);
if (phoneMatch) visitorContact = phoneMatch[1];
const emailMatch = msg.match(/([a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,})/i);
if (emailMatch && !visitorContact) visitorContact = emailMatch[1];

const hasContactData = !!(visitorName || visitorContact);

const kbRows = $('Leer KB').all();
let kbText = '';
if (kbRows && kbRows.length > 0) {
  kbText = kbRows.map(r => r.json.Tema + ': ' + r.json.Contenido).join('\n');
}

const systemPrompt = `Eres el asistente virtual de ${businessName}...
BASE DE CONOCIMIENTO DEL NEGOCIO:
${kbText}
PAUTAS: Responde en espanol, usa los datos de la KB, pide contacto si hay intencion de compra, no inventes`;

const messages = [{ role: 'system', content: systemPrompt }];
const recentHistory = history.slice(-8);
for (const h of recentHistory) messages.push({ role: h.role, content: h.content });
messages.push({ role: 'user', content: msg });

return [{ json: { userId, sessionId, message: msg, visitorName, visitorContact, hasContactData, businessName, timestamp: new Date().toISOString(), deepseekPayload: JSON.stringify({ model: 'deepseek-chat', messages, temperature: 0.7, max_tokens: 800 }) } }];

const data = $input.first().json;
const text = data.choices?.[0]?.message?.content || 'Error';
const prepData = $('Prepare DeepSeek').first().json;

let estado = 'Rebote';
if (prepData.hasContactData) estado = 'Lead caliente';
else if (prepData.message && prepData.message.length > 5) estado = 'Consulta';

const frases = text.split(/[.!?]\s+/);
const resumen = frases.slice(0, 2).join('. ').substring(0, 200);

const temas = [];
if (/precio|cuánto|cuesta/i.test(prepData.message)) temas.push('Precios');
if (/reserva|mesa|disponib/i.test(prepData.message)) temas.push('Reservas');
if (/carta|menú|plato/i.test(prepData.message)) temas.push('Carta/Menú');
if (/horario|abren/i.test(prepData.message)) temas.push('Horario');
if (temas.length === 0) temas.push('General');

const confianza = data.choices?.[0]?.finish_reason === 'stop' ? 'Alta' : 'Media';

return [{ json: { response: text, sessionId: prepData.sessionId, visitorName: prepData.visitorName || '', visitorContact: prepData.visitorContact || '', hasContactData: prepData.hasContactData, businessName: prepData.businessName, userMessage: prepData.message, timestamp: prepData.timestamp, estado, resumen, temas: temas.join(', '), confianza } }];
